  .word	EXTI3_2_IRQHandler                                      			/* EXTI line 1 interrupt through EXTI                                                                                   */
  .word	EXTI15_4_IRQHandler                                     			/* EXTI line 2 interrupt through EXTI                                                                                   */
  .word	ADC_COMP_DAC_IRQHandler                                 			/* ADC and DAC global interrupt,COMP1 and COMP2 interrupt through EXTI                                                  */
  .word	DMA1_CH3_1_IRQHandler                                   			/* DMA1 channel 3:1 secure and non-secure interrupt (C2IMR2[2:0])                                                       */
  .word	DMA1_CH7_4_IRQHandler                                   			/* DMA1 channel 7:4 secure and non-secure interrupt (C2IMR2[6:3])                                                       */
