  .word	LPTIM1_IRQHandler                                       			/* LPtimer 1 global interrupt                                                                                           */
  .word	LPTIM2_IRQHandler                                       			/* LPtimer 2 global interrupt                                                                                           */
  .word	LPTIM3_IRQHandler                                       			/* LPtimer 3 global interrupt                                                                                           */
  .word	TIM1_BRK_TIM1_UP_TIM1_TRG_COM_TIM1_CC_IRQHandler        			/* Timer 1 break, update, trigger and communication,capture compare interrupt                                           */
  .word	TIM2_IRQHandler                                         			/* Timer 2 global interrupt                                                                                             */
  .word	TIM16_IRQHandler                                        			/* Timer 16 global interrupt                                                                                            */
  .word	TIM17_IRQHandler                                        			/* Timer 17 global interrupt                                                                                            */
  .word	IPCC_C2_RX_IT_IPCC_C2_TX_IT_IRQHandler                  			/* IPCC CPU2 RX occupied interrupt, IPCC CPU2 TX free interrupt                                                         */
  .word	HSEM_IRQHandler                                         			/* Semaphore interrupt 1 to CPU2                                                                                        */
  .word	True_RNG_IRQHandler                                     			/* True random number generator interrupt                                                                               */
  .word	AES_PKA_IRQHandler                                      			/* AES global interrupt , Private key accelerator interrupt                                                             */
  .word	I2C1_EV_I2C1_ER_IRQHandler                              			/* I2C1 event interrupt,I2C1 error interrupt                                                                            */
  .word	I2C2_EV_I2C2_ER_IRQHandler                              			/* I2C2 event interrupt , I2C2 error interrupt                                                                          */
